#!/bin/bash

WAL_COLORS="$HOME/.cache/wal/colors.sh"
QML_COLORS="$HOME/.config/quickshell/kriti-shell/Colors.qml"

# stop if pywal hasn’t run
[ -f "$WAL_COLORS" ] || exit 1

# load wal colors
source "$WAL_COLORS"

cat > "$QML_COLORS" << EOF
// Auto-generated by pywal
// Do not edit unless you wanna waste time

pragma Singleton

import Quickshell
import QtQuick

Singleton {
  readonly property bool isDark: true

  // Backgrounds
  readonly property color mainPanelBackground: "$background"
  readonly property color itemBackground: "$color0"
  readonly property color itemHoveredBackground: "$color8"
  readonly property color itemPressedBackground: "$color7"
  readonly property color itemDisabledBackground: "$background"

  // Text
  readonly property color text: "$foreground"
  readonly property color bigText: "$foreground"
  readonly property color smallText: "$color8"

  // Accents / separators
  readonly property color separator: "$color0"
  readonly property color itemWarningBackground: "$color1"

  readonly property int colorTransitionTime: 50
}
EOF

echo "✓ Quickshell colors updated from pywal"

